function handleCommand(fullCommand) {
    const trimmedCommand = fullCommand.trim();
    if (!trimmedCommand) { // If empty command, just show prompt again
        printToCli('', true, ''); // Effectively gives a new prompt line
        return;
    }

    const parts = trimmedCommand.toLowerCase().split(' ');
    const command = parts[0];
    const args = parts.slice(1);

    printToCli('', true, trimmedCommand); // Echo command

    if (command === 'exit') {
        toggleCliMode();
        return;
    }

    const responseFunction = cliCommands[command];
    let response;

    if (responseFunction) {
        response = typeof responseFunction === 'function' ? responseFunction(args) : responseFunction;
    } else {
        response = `<span class="gruv-red">Command not found:</span> ${command}. Type "help" for available commands.`;
    }

    if (response) printToCli(response);
}


// Scroll to Top Button Functionality
const scrollToTopBtn = document.getElementById('scrollToTopBtn');

function checkScroll() {
    if (!scrollToTopBtn) return;
    if (window.scrollY > 300) { // Show button after scrolling 300px
        scrollToTopBtn.classList.remove('hidden');
    } else {
        scrollToTopBtn.classList.add('hidden');
    }
}

function scrollToTop() {
    window.scrollTo({ top: 0, behavior: 'smooth' });
}


// Initialize
document.addEventListener('DOMContentLoaded', () => {
    updateTerminal();
    loadProjects();
    typeBio();
    loadCTFChallenges();

    if (bunnyTrigger) bunnyTrigger.addEventListener('click', toggleCliMode);
    
    if (cliCommandInput) {
        cliCommandInput.addEventListener('keypress', (e) => {
            if (e.key === 'Enter') {
                const commandText = e.target.value.trim();
                // No need to check if commandText is empty here, handleCommand will do it
                if (commandHistory[commandHistory.length -1] !== commandText || commandText === "") { // Allow empty submits to not clutter history much but still work
                    commandHistory.push(commandText);
                }
                historyIndex = commandHistory.length;
                handleCommand(commandText);
                e.target.value = '';
            }
        });
        cliCommandInput.addEventListener('keydown', (e) => {
            if (e.key === 'ArrowUp') {
                if (historyIndex > 0) {
                    historyIndex--;
                    e.target.value = commandHistory[historyIndex];
                    e.target.setSelectionRange(e.target.value.length, e.target.value.length);
                }
                e.preventDefault();
            } else if (e.key === 'ArrowDown') {
                if (historyIndex < commandHistory.length - 1) {
                    historyIndex++;
                    e.target.value = commandHistory[historyIndex];
                    e.target.setSelectionRange(e.target.value.length, e.target.value.length);
                } else {
                    historyIndex = commandHistory.length;
                    e.target.value = '';
                }
                e.preventDefault();
            } else if (e.key === 'Tab') { // Basic Tab Autocomplete (very simple example)
                e.preventDefault();
                const currentInput = e.target.value.toLowerCase().trim();
                const suggestions = Object.keys(cliCommands).filter(cmd => cmd.startsWith(currentInput));
                if (suggestions.length === 1) {
                    e.target.value = suggestions[0] + ' '; // Add space for args
                } else if (suggestions.length > 1) {
                    printToCli(`Suggestions: <span class="gruv-yellow">${suggestions.join(', ')}</span>`);
                }
            }
        });
        cliCommandInput.addEventListener('focus', function() {
            setTimeout(() => {
                this.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
            }, 100);
        });
    }

    const themeToggleButton = document.getElementById('themeToggle');
    if (themeToggleButton) {
        themeToggleButton.addEventListener('click', () => {
            document.body.classList.toggle('light-theme');
            const icon = document.getElementById('themeIcon');
            if (icon) {
                if (document.body.classList.contains('light-theme')) {
                    icon.classList.remove('fa-moon'); icon.classList.add('fa-sun');
                } else {
                    icon.classList.remove('fa-sun'); icon.classList.add('fa-moon');
                }
            }
        });
    }

    document.querySelectorAll('.filter-btn').forEach(btn => {
        btn.addEventListener('click', () => {
            document.querySelectorAll('.filter-btn').forEach(b => b.classList.remove('active'));
            btn.classList.add('active');
            const filter = btn.getAttribute('data-filter');
            const projects = document.querySelectorAll('#github-projects .project-card');
            let visibleCount = 0;
            projects.forEach((project, index) => {
                const projectCategory = project.getAttribute('data-category');
                const matchesFilter = (filter === 'all' || projectCategory === filter);
                
                if (matchesFilter) {
                    project.style.display = 'flex';
                    // Re-apply animation with a slight delay based on its new visible index
                    project.style.animationDelay = `${visibleCount * 0.07}s`;
                    project.classList.remove('fadeInSlideUpItem'); // Remove to re-trigger
                    void project.offsetWidth; // Trigger reflow
                    project.classList.add('fadeInSlideUpItem');
                    visibleCount++;
                } else {
                    project.style.display = 'none';
                }
            });
        });
    });
    
    // Scroll to Top listener
    if (scrollToTopBtn) {
        window.addEventListener('scroll', checkScroll);
        scrollToTopBtn.addEventListener('click', scrollToTop);
    }

    // Set initial active section button and visibility
    const initialSection = 'projects'; // Default to projects
    toggleSection(initialSection); // This will also handle active button class
    // Ensure only the initial section is visible by explicitly hiding others if toggleSection doesn't fully handle it on first load
    ['certificates', 'ctf', 'contact'].forEach(id => {
        if (id !== initialSection) {
            const el = document.getElementById(`${id}Section`);
            if (el) {
                el.classList.remove('visible');
                el.classList.add('hidden'); // Ensure it's fully hidden initially
            }
        }
    });
});
